import React from 'react';
import { ListItemLike, ListItem, ListItemTitle, ListItemDesc, ListCaption, ListEmpty, ListDivider } from '.';
import { snapshotTest } from '../../../../test-utils/shared/mountTest';

describe('List > ListItem testings', () => {
  snapshotTest('ListItemLike', <ListItemLike />);
  snapshotTest('ListItem', <ListItem />);
  snapshotTest('ListItem active', <ListItem active />);
  snapshotTest('ListItem disabled', <ListItem disabled />);
  snapshotTest('ListItem selected', <ListItem selected />);
  snapshotTest('ListItem after', <ListItem after="after" />);
  snapshotTest('ListItem children', <ListItem>children</ListItem>);
  snapshotTest('ListItem showCheckmark={false}', <ListItem showCheckmark={false} />);
  snapshotTest('ListItem after showCheckmark={ture}', <ListItem after="after" showCheckmark={true} />);
  // Title
  snapshotTest('ListItemTitle', <ListItemTitle />);
  snapshotTest('ListItemTitle before', <ListItemTitle before="before" />);
  snapshotTest('ListItemTitle children', <ListItemTitle>children</ListItemTitle>);
  snapshotTest('ListItemTitle textOverflow={true} children', <ListItemTitle textOverflow>children</ListItemTitle>);
  snapshotTest(
    'ListItemTitle textOverflow={false} children',
    <ListItemTitle textOverflow={false}>children</ListItemTitle>,
  );
  // Desc
  snapshotTest('ListItemDesc', <ListItemDesc />);
  snapshotTest('ListCaption', <ListCaption />);
  snapshotTest('ListEmpty', <ListEmpty />);
  snapshotTest('ListDivider', <ListDivider />);
  snapshotTest('ListDivider fluid={true}', <ListDivider fluid />);
  snapshotTest("ListDivider marginBlock={'start'}", <ListDivider marginBlock="start" />);
  snapshotTest("ListDivider marginBlock={'end'}", <ListDivider marginBlock="end" />);
});
